#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=23000005;
int n,m,cnt,a[N];
int tr[N],ls[N],rs[N],num[N];
int build(int x,int y)
{
	int id=++cnt;
	if(x==y)
	{
		tr[id]=a[x];
		return id;
	}
	int mid=(x+y)/2;
	ls[id]=build(x,mid);
	rs[id]=build(mid+1,y);
	return id;
}
int update(int id,int x,int y,int z,int val)
{
	tr[++cnt]=tr[id];
	ls[cnt]=ls[id];
	rs[cnt]=rs[id];
	id=cnt;
	if(x==y)
	{
		tr[id]=val;
		return id;
	}
	int mid=(x+y)/2;
	if(z<=mid) ls[id]=update(ls[id],x,mid,z,val);
	else rs[id]=update(rs[id],mid+1,y,z,val);
	return id;
}
int query(int id,int x,int y,int z)
{
	if(x==y) return tr[id];
	int mid=(x+y)/2;
	if(z<=mid) return query(ls[id],x,mid,z);
	else return query(rs[id],mid+1,y,z);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	num[0]=1;
	build(1,n);
	for(int i=1;i<=m;i++) 
	{
		int x,y,z;
		cin>>x>>y>>z;
		if(y==1)
		{
			int val;
			cin>>val;
			num[i]=cnt+1;
			update(num[x],1,n,z,val);
		}
		else
		{
			cout<<query(num[x],1,n,z)<<"\n";
			num[i]=num[x];
		}
	}
	return 0;
}
